class Solution:
    def countPrimeSetBits(self, left, right):
        def is_prime(x):
            if x < 2:
                return False
            i = 2
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 1
            return True
        count = 0
        for v in range(left, right + 1):
            if is_prime(bin(v).count('1')):
                count += 1
        return count

