class Solution:
    def countPrimeSetBits(self, left, right):
        primes = {2, 3, 5, 7, 11, 13, 17, 19}
        count = 0
        for v in range(left, right + 1):
            if bin(v).count('1') in primes:
                count += 1
        return count

