var countPrimeSetBits = function(left, right) {
    const primes = new Set([2, 3, 5, 7, 11, 13, 17, 19]);
    let count = 0;
    for (let v = left; v <= right; v++) {
        let bits = 0, x = v;
        while (x > 0) { bits += x & 1; x >>>= 1; }
        if (primes.has(bits)) count++;
    }
    return count;
};
